const input = $input.first().json;
const action = input.action || '';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.unsplash&cred_key=eq.unsplash_access_key&select=cred_value',
  headers: pgHeaders
});
if (!creds || !creds[0] || !creds[0].cred_value) {
  return [{ json: { error: 'Unsplash Access Key not configured. Use add_credential to set it up.' } }];
}
const accessKey = creds[0].cred_value;
const API = 'https://api.unsplash.com';
const authHeaders = { 'Authorization': 'Client-ID ' + accessKey, 'Accept-Version': 'v1' };
const UTM = '?utm_source=n8n-claw&utm_medium=referral';

const validOrientations = ['landscape', 'portrait', 'squarish'];

function formatPhoto(p) {
  const desc = p.description || p.alt_description || '(no description)';
  const photographer = p.user ? p.user.name : 'Unknown';
  const photographerLink = (p.user && p.user.links && p.user.links.html) ? (p.user.links.html + UTM) : '';
  const photoLink = (p.links && p.links.html) ? (p.links.html + UTM) : '';
  let out = '**' + desc + '**\n';
  out += 'ID: ' + p.id + '\n';
  if (p.width && p.height) out += 'Size: ' + p.width + 'x' + p.height + '\n';
  if (p.color) out += 'Color: ' + p.color + '\n';
  if (typeof p.likes === 'number') out += 'Likes: ' + p.likes + '\n';
  if (p.urls) {
    out += 'Image (regular): ' + p.urls.regular + '\n';
    out += 'Image (small): ' + p.urls.small + '\n';
  }
  out += 'Photo page: ' + photoLink + '\n';
  out += 'Photo by ' + photographer + ' on Unsplash' + (photographerLink ? ' (' + photographerLink + ')' : '') + '\n';
  return out;
}

// === search_photos ===
if (action === 'search_photos') {
  const query = input.query;
  if (!query) {
    return [{ json: { error: 'Parameter "query" is required. Examples: "mountains", "coffee", "berlin skyline".' } }];
  }
  const limit = Math.min(parseInt(input.limit) || 5, 20);
  const orientation = input.orientation;
  let url = API + '/search/photos?query=' + encodeURIComponent(query) + '&per_page=' + limit;
  if (orientation && validOrientations.includes(orientation)) {
    url += '&orientation=' + orientation;
  }

  try {
    const data = await helpers.httpRequest({ method: 'GET', url, headers: authHeaders });
    const results = data.results || [];
    if (results.length === 0) {
      return [{ json: { result: 'No photos found for: ' + query } }];
    }
    let out = 'Found ' + data.total + ' photos for "' + query + '", showing top ' + results.length + ':\n\n';
    for (const p of results) {
      out += formatPhoto(p) + '\n';
    }
    out += '---\nImages hosted on Unsplash (https://unsplash.com' + UTM + '). Attribution required when displayed.';
    if (out.length > 5000) out = out.substring(0, 5000) + '\n... (truncated)';
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'Unsplash search failed: ' + err.message } }];
  }

// === get_random_photo ===
} else if (action === 'get_random_photo') {
  const query = input.query;
  const orientation = input.orientation;
  let url = API + '/photos/random';
  const params = [];
  if (query) params.push('query=' + encodeURIComponent(query));
  if (orientation && validOrientations.includes(orientation)) params.push('orientation=' + orientation);
  if (params.length > 0) url += '?' + params.join('&');

  try {
    const data = await helpers.httpRequest({ method: 'GET', url, headers: authHeaders });
    if (!data || !data.id) {
      return [{ json: { error: 'No random photo returned' + (query ? ' for query: ' + query : '') + '.' } }];
    }
    let out = 'Random photo' + (query ? ' for "' + query + '"' : '') + ':\n\n';
    out += formatPhoto(data) + '\n';
    out += '---\nImage hosted on Unsplash (https://unsplash.com' + UTM + '). Attribution required when displayed.';
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'Unsplash random photo failed: ' + err.message } }];
  }

// === get_photo ===
} else if (action === 'get_photo') {
  const photoId = input.photo_id;
  if (!photoId) {
    return [{ json: { error: 'Parameter "photo_id" is required (e.g. eAAjKAGEKmI from search_photos).' } }];
  }

  try {
    const p = await helpers.httpRequest({
      method: 'GET',
      url: API + '/photos/' + encodeURIComponent(photoId),
      headers: authHeaders
    });
    let out = formatPhoto(p) + '\n';
    if (p.tags && p.tags.length > 0) {
      const tagTitles = p.tags.map(t => t.title).slice(0, 10);
      out += 'Tags: ' + tagTitles.join(', ') + '\n';
    }
    if (p.location && (p.location.city || p.location.country || p.location.name)) {
      const loc = [p.location.city, p.location.country].filter(Boolean).join(', ') || p.location.name;
      out += 'Location: ' + loc + '\n';
    }
    if (p.urls && p.urls.raw) out += 'Image (raw): ' + p.urls.raw + '\n';
    out += '\nImage hosted on Unsplash (https://unsplash.com' + UTM + '). Attribution required when displayed.';
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'Unsplash get_photo failed: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: "' + action + '". Available: search_photos, get_random_photo, get_photo.' } }];
}
